import React, { useState, useEffect, useRef } from 'react';
import { useChat } from '../../contexts/ChatContext';
import { useAuth } from '../../contexts/AuthContext';
import axios from 'axios';
import { Send, User, MessageCircle, Filter, Search } from 'lucide-react';

const ChatSuporte = () => {
  const { sessoesAtivas, mensagens, enviarMensagem, atenderSessao, carregarMensagens } = useChat();
  const { admin } = useAuth();
  const [sessaoSelecionada, setSessaoSelecionada] = useState(null);
  const [novaMensagem, setNovaMensagem] = useState('');
  const [filtro, setFiltro] = useState('todas'); // todas, ativas, minha
  const [busca, setBusca] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    loadSessoes();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [mensagens, sessaoSelecionada]);

  const loadSessoes = async () => {
    try {
      const response = await axios.get('/api/admin/chat/sessoes');
      // setSessoesAtivas(response.data);
    } catch (error) {
      console.error('Erro ao carregar sessões:', error);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleAtenderSessao = async (sessao) => {
    setLoading(true);
    const result = await atenderSessao(sessao.sessao_id);
    if (result.success) {
      setSessaoSelecionada(sessao);
      await carregarMensagens(sessao.sessao_id);
    }
    setLoading(false);
  };

  const handleEnviarMensagem = async (e) => {
    e.preventDefault();
    if (!novaMensagem.trim() || !sessaoSelecionada) return;

    const result = await enviarMensagem(sessaoSelecionada.sessao_id, novaMensagem);
    if (result.success) {
      setNovaMensagem('');
    }
  };

  const sessoesFiltradas = sessoesAtivas.filter(sessao => {
    const matchesBusca = !busca || 
      sessao.cliente_email?.toLowerCase().includes(busca.toLowerCase()) ||
      sessao.cliente_nome?.toLowerCase().includes(busca.toLowerCase());

    const matchesFiltro = filtro === 'todas' || 
      (filtro === 'ativas' && sessao.status === 'ativa') ||
      (filtro === 'minha' && sessao.atendente_id === admin.id);

    return matchesBusca && matchesFiltro;
  });

  return (
    <div className="h-[calc(100vh-8rem)]">
      <div className="bg-white rounded-lg shadow h-full">
        <div className="flex h-full">
          {/* Lista de Sessões */}
          <div className="w-80 border-r border-gray-200 flex flex-col">
            <div className="p-4 border-b border-gray-200">
              <h2 className="text-lg font-semibold text-gray-900 mb-4">Sessões de Chat</h2>

              {/* Filtros */}
              <div className="space-y-3">
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
                  <input
                    type="text"
                    placeholder="Buscar cliente..."
                    value={busca}
                    onChange={(e) => setBusca(e.target.value)}
                    className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
                  />
                </div>

                <select
                  value={filtro}
                  onChange={(e) => setFiltro(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
                >
                  <option value="todas">Todas as sessões</option>
                  <option value="ativas">Apenas ativas</option>
                  <option value="minha">Minhas sessões</option>
                </select>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto">
              {sessoesFiltradas.length === 0 ? (
                <div className="p-4 text-center text-gray-500">
                  <MessageCircle className="h-8 w-8 mx-auto mb-2 text-gray-300" />
                  <p>Nenhuma sessão encontrada</p>
                </div>
              ) : (
                <div className="space-y-1">
                  {sessoesFiltradas.map((sessao) => (
                    <div
                      key={sessao.sessao_id}
                      onClick={() => handleAtenderSessao(sessao)}
                      className={`p-3 cursor-pointer transition-colors ${
                        sessaoSelecionada?.sessao_id === sessao.sessao_id
                          ? 'bg-blue-50 border-l-4 border-blue-500'
                          : 'hover:bg-gray-50'
                      }`}
                    >
                      <div className="flex items-start justify-between">
                        <div className="flex items-start">
                          <div className="bg-gray-200 rounded-full p-2">
                            <User className="h-4 w-4 text-gray-600" />
                          </div>
                          <div className="ml-3 flex-1">
                            <p className="text-sm font-medium text-gray-900">
                              {sessao.cliente_nome || 'Cliente'}
                            </p>
                            <p className="text-xs text-gray-500">
                              {sessao.cliente_email}
                            </p>
                            <p className="text-xs text-gray-400 mt-1">
                              {new Date(sessao.data_inicio).toLocaleString('pt-BR', {
                                hour: '2-digit',
                                minute: '2-digit'
                              })}
                            </p>
                          </div>
                        </div>
                        <div className="flex flex-col items-end">
                          <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                            sessao.status === 'ativa' 
                              ? 'bg-green-100 text-green-800'
                              : 'bg-gray-100 text-gray-800'
                          }`}>
                            {sessao.status === 'ativa' ? 'Ativo' : 'Inativo'}
                          </span>
                          {sessao.atendente_id && (
                            <span className="text-xs text-gray-500 mt-1">
                              Atendente #{sessao.atendente_id}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Área do Chat */}
          <div className="flex-1 flex flex-col">
            {sessaoSelecionada ? (
              <>
                {/* Header do Chat */}
                <div className="p-4 border-b border-gray-200 bg-gray-50">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center">
                      <div className="bg-blue-600 rounded-full p-2">
                        <User className="h-4 w-4 text-white" />
                      </div>
                      <div className="ml-3">
                        <p className="text-sm font-medium text-gray-900">
                          {sessaoSelecionada.cliente_nome || 'Cliente'}
                        </p>
                        <p className="text-xs text-gray-500">
                          {sessaoSelecionada.cliente_email}
                        </p>
                      </div>
                    </div>
                    <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                      sessaoSelecionada.status === 'ativa' 
                        ? 'bg-green-100 text-green-800'
                        : 'bg-gray-100 text-gray-800'
                    }`}>
                      {sessaoSelecionada.status === 'ativa' ? 'Sessão Ativa' : 'Sessão Encerrada'}
                    </span>
                  </div>
                </div>

                {/* Mensagens */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4">
                  {mensagens[sessaoSelecionada.sessao_id]?.map((mensagem) => (
                    <div
                      key={mensagem.id}
                      className={`flex ${mensagem.remetente === 'atendente' ? 'justify-end' : 'justify-start'}`}
                    >
                      <div className={`max-w-xs lg:max-w-md px-4 py-2 rounded-lg ${
                        mensagem.remetente === 'atendente'
                          ? 'bg-blue-600 text-white'
                          : 'bg-gray-100 text-gray-900'
                      }`}>
                        <p className="text-sm">{mensagem.mensagem}</p>
                        <p className={`text-xs mt-1 ${
                          mensagem.remetente === 'atendente' ? 'text-blue-100' : 'text-gray-500'
                        }`}>
                          {new Date(mensagem.data_criacao).toLocaleString('pt-BR', {
                            hour: '2-digit',
                            minute: '2-digit'
                          })}
                        </p>
                      </div>
                    </div>
                  ))}
                  <div ref={messagesEndRef} />
                </div>

                {/* Input de Mensagem */}
                {sessaoSelecionada.status === 'ativa' && (
                  <form onSubmit={handleEnviarMensagem} className="p-4 border-t border-gray-200">
                    <div className="flex space-x-2">
                      <input
                        type="text"
                        value={novaMensagem}
                        onChange={(e) => setNovaMensagem(e.target.value)}
                        placeholder="Digite sua mensagem..."
                        className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        disabled={loading}
                      />
                      <button
                        type="submit"
                        disabled={loading || !novaMensagem.trim()}
                        className="bg-blue-600 text-white p-2 rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50"
                      >
                        <Send className="h-5 w-5" />
                      </button>
                    </div>
                  </form>
                )}
              </>
            ) : (
              <div className="flex-1 flex items-center justify-center">
                <div className="text-center">
                  <MessageCircle className="h-12 w-12 text-gray-300 mx-auto mb-4" />
                  <p className="text-gray-500">Selecione uma sessão para começar</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatSuporte;
